insert into public.exhibitions (id, slug, title_en, title_ro, subtitle_en, subtitle_ro, overview_en, overview_ro, start_date, end_date, venue_en, venue_ro, poster_url, published, sort_order) values ('f4eaab9d-2e61-5063-99b5-945f2ff70cb8', 'acest-spatiu-nu-exista', 'This Space Does Not Exist', 'Acest spațiu nu există', 'Itinerant solo exhibition', 'Itinerant solo exhibition', 'The itinerant exhibition project “This Space Does Not Exist” interrogates concepts such as memory, space, and identity. Pursuing an ostensibly documentary intent, the images are, for the most part, staged constructions that explore the theme of identity in relation to the effects of the passage of time. Thus, the image of the self is constructed in relation to the image of the other—namely, “the family”. The narrative dimension of the works can also be understood from the perspective of the scenography proposed by the artist, who, through various associations of elements—whether photographs, personal objects, or documents—manages in some way to blur the boundaries between the real and the imaginary. The perspective becomes symbolic, distancing itself from the perceived reality.', 'The itinerant exhibition project “This Space Does Not Exist” interrogates concepts such as memory, space, and identity. Pursuing an ostensibly documentary intent, the images are, for the most part, staged constructions that explore the theme of identity in relation to the effects of the passage of time. Thus, the image of the self is constructed in relation to the image of the other—namely, “the family”. The narrative dimension of the works can also be understood from the perspective of the scenography proposed by the artist, who, through various associations of elements—whether photographs, personal objects, or documents—manages in some way to blur the boundaries between the real and the imaginary. The perspective becomes symbolic, distancing itself from the perceived reality.', '2024-10-03', '2024-11-03', '03.10-03.11.2024, “Gheorghe Naum” Gallery, Brăila Museum “Carol I”, Brăila, Romania', '03.10-03.11.2024, “Gheorghe Naum” Gallery, Brăila Museum “Carol I”, Brăila, Romania', 'https://rptwowkkejecvvbfsgkt.supabase.co/storage/v1/object/public/artwork-images/wp-import/exhibitions/acest-spatiu-nu-exista/vernisaj-andreea-gabriela-tudor-24.jpg', true, 0) on conflict (slug) do update set title_en=excluded.title_en, title_ro=excluded.title_ro, subtitle_en=excluded.subtitle_en, poster_url=excluded.poster_url, venue_en=excluded.venue_en, start_date=excluded.start_date, end_date=excluded.end_date, published=true;
