insert into public.exhibitions (id, slug, title_en, title_ro, subtitle_en, subtitle_ro, overview_en, overview_ro, start_date, end_date, venue_en, venue_ro, poster_url, published, sort_order) values ('26d9b531-18b7-565c-a751-739fac1d5d5c', 'forget-me-not', 'Forget-Me-Not', 'Floare de nu-mă-uita', 'Duo-exhibition', 'Duo-exhibition', 'Gardens have always functioned as spaces of refuge, where inward reflection is deepened by the patience and tranquility of nature, as human presence is enveloped by the eternal beauty of vegetal forms.The exhibitionForget-Me-Notevokes a horizon of memory—of enduring bonds woven into the fabric of existence—interpreted through two distinct chromatic approaches by artists Andreea Gabriela Tudor and Lavinia Maria Oniciuc.
