insert into public.exhibitions (id, slug, title_en, title_ro, subtitle_en, subtitle_ro, overview_en, overview_ro, start_date, end_date, venue_en, venue_ro, poster_url, published, sort_order) values ('02b40153-bd43-504e-a3f2-e5f2e7058262', 'pigments-of-affective-contact-ro-pigmenti-de-contact-afectiv', 'Pigments of Affective Contact', 'Pigmenți de contact afectiv', 'Itinerant group exhibition', 'Itinerant group exhibition', 'The exhibitionPigments of Affective Contactbrings together four women artists who employ the body—their own or that of the other—as a territory for exploring emotion, memory, and vulnerability. In their works, skin becomes a site where color merges with memory, and the artistic act is transformed into a gesture of tenderness. Color, or pigment, functions as an extension of the human skin—an imprint of emotion that reaches the viewer through layers of sensitivity. Thus, the body no longer appears as a mere object to be looked at, but as an affective landscape in which the boundaries between the visible and the invisible are continuously redefined.
