insert into public.exhibitions (id, slug, title_en, title_ro, subtitle_en, subtitle_ro, overview_en, overview_ro, start_date, end_date, venue_en, venue_ro, poster_url, published, sort_order) values ('8e04b2fb-58ec-5604-b031-157d81647301', 'the-gift-of-vision', 'The Gift of Vision', 'Darul vederii', 'Itinerant group exhibition', 'Itinerant group exhibition', 'The exhibition’s theme is the centrality of vision—understood both in its common sense of visual perception and in its more specific meaning of attention and discernment—for the act of painting and for the life of the spirit alike. Though far from new, the theme is nevertheless inexhaustible. It is continually renewed and diversified in conjunction with the sensibility of each of the four artists, while simultaneously offering a ground for encounter and dialogue. The exhibition presents four distinct perspectives on nature, four different ways of apprehending and interpreting the material reality of the world.
